class Solution {
    public int repeatedStringMatch(String a, String b) {
        int n = a.length();
        int m = b.length();
        int count = (m + n - 1) / n;
        String repeated = repeatString(a, count);
        if (repeated.contains(b)) return count;
        if (count > 1 && repeatString(a, count - 1).contains(b)) return count - 1;
        return -1;
    }

    private String repeatString(String a, int count) {
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < count; i++) {
            sb.append(a);
        }
        return sb.toString();
    }
}
```
